import json
import re
from datetime import datetime
from collections import defaultdict, Counter

# Get the file path from storage
file_path = var_functions.query_db_50
print(f"Loading data from: {file_path}")

# Load the patent data
with open(file_path, 'r') as f:
    patents_data = json.load(f)

print(f"Total patents loaded: {len(patents_data)}")

# Function to extract German title from title_localized
def extract_german_title(title_json):
    """Extract German title from title_localized JSON string"""
    if not title_json:
        return "N/A"
    try:
        titles = json.loads(title_json)
        for title in titles:
            if isinstance(title, dict) and title.get('language') == 'de':
                return title.get('text', 'N/A')
    except:
        pass
    return "N/A"

# Function to extract CPC codes at level 4
def extract_cpc_level4(cpc_json):
    """Extract CPC level 4 codes from CPC JSON string"""
    if not cpc_json:
        return []
    try:
        cpc_list = json.loads(cpc_json)
        level4_codes = set()
        for item in cpc_list:
            if isinstance(item, dict) and 'code' in item:
                code = item['code']
                # Extract first 4 characters for level 4
                if len(code) >= 4:
                    level4_codes.add(code[:4])
    except:
        pass
    return list(level4_codes)

# Function to parse grant date
def parse_grant_date(date_str):
    """Parse grant date string to datetime object"""
    if not date_str or '2019' not in date_str:
        return None

    # Clean up the date string
    date_str = date_str.lower()
    date_str = re.sub(r'(dated|the|rd|th|st|nd|,)', '', date_str)
    date_str = date_str.strip()

    # Common month abbreviations
    months = {
        'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6,
        'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12
    }

    # Try to extract month and check if it's second half
    for month_abbr, month_num in months.items():
        if month_abbr in date_str:
            if month_num >= 7:  # Second half: July to December
                try:
                    # Try to parse the full date
                    parts = date_str.split()
                    for part in parts:
                        if part.isdigit() and len(part) <= 2:
                            day = int(part)
                        elif len(part) == 4 and part.isdigit():
                            year = int(part)
                    return datetime(2019, month_num, day)
                except:
                    # If parsing fails, just return month info
                    return datetime(2019, month_num, 1)
    return None

# Process patents
second_half_patents = []
cpc_counts = Counter()  # Count patents per CPC level 4
cpc_titles = defaultdict(list)  # Store titles for each CPC code

for patent in patents_data:
    grant_date_str = patent.get('grant_date', '')

    # Skip if not second half of 2019
    grant_date = parse_grant_date(grant_date_str)
    if not grant_date:
        continue

    # Extract CPC codes at level 4
    cpc_codes = extract_cpc_level4(patent.get('cpc', ''))
    if not cpc_codes:
        continue

    # Extract German title
    german_title = extract_german_title(patent.get('title_localized', ''))

    # Store patent info
    second_half_patents.append({
        'grant_date': grant_date,
        'cpc_codes': cpc_codes,
        'title': german_title
    })

    # Count CPC codes
    for code in cpc_codes:
        cpc_counts[code] += 1
        if german_title != "N/A":
            cpc_titles[code].append(german_title)

print(f"\nPatents in second half of 2019: {len(second_half_patents)}")
print(f"Unique CPC level 4 codes: {len(cpc_counts)}")

# Show top CPC codes by count
print("\nTop 10 CPC codes by patent count:")
for code, count in cpc_counts.most_common(10):
    print(f"  {code}: {count} patents")

result_summary = {
    'total_second_half_patents': len(second_half_patents),
    'unique_cpc_codes': len(cpc_counts),
    'top_cpc_codes': cpc_counts.most_common(10)
}

print("__RESULT__:")
print(json.dumps(result_summary))

