import re
from collections import defaultdict, Counter

# Get file path
file_path = var_functions.query_db_78
with open(file_path, 'r') as f:
    patents = json.load(f)

print(f"Loaded {len(patents)} patents")

# Extract month from grant date
def get_month(date_str):
    if not date_str:
        return None
    date_str = date_str.lower()
    months = {
        'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6,
        'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12
    }
    for abbr, num in months.items():
        if abbr in date_str:
            return num
    return None

# Extract CPC level 4 codes
def get_cpc_level4(cpc_json):
    if not cpc_json or cpc_json == '[]':
        return []
    try:
        cpc_list = json.loads(cpc_json)
        codes = set()
        for item in cpc_list:
            if isinstance(item, dict) and 'code' in item:
                code = item['code']
                if len(code) >= 4:
                    codes.add(code[:4])
        return list(codes)
    except:
        return []

# Count patents per CPC per month (second half 2019)
cpc_counts = defaultdict(lambda: defaultdict(int))
second_half_total = 0

for patent in patents:
    date_str = patent.get('grant_date', '')
    if not date_str or '2019' not in date_str:
        continue

    month = get_month(date_str)
    if not month or month < 7:  # Only second half (July-December)
        continue

    cpc_codes = get_cpc_level4(patent.get('cpc', ''))
    if not cpc_codes:
        continue

    second_half_total += 1
    for cpc in cpc_codes:
        cpc_counts[cpc][month] += 1

print(f"Second half 2019 patents: {second_half_total}")
print(f"Unique CPC level 4 codes: {len(cpc_counts)}")

# Calculate EMA for each CPC
alpha = 0.1
best_periods = {}

for cpc in cpc_counts:
