            ema = alpha * count + (1 - alpha) * ema

        if ema > best_ema:
            best_ema = ema
            best_month = month
            best_count = count

    best_periods[cpc] = {
        'best_ema': best_ema,
        'best_month': best_month,
        'patents_in_month': best_count
    }

# Sort by best EMA
sorted_cpc = sorted(best_periods.items(), key=lambda x: x[1]['best_ema'], reverse=True)

print(f"\nTop 15 CPC codes by EMA:")
