import json
import re
from collections import defaultdict

# Get file path from the available variables
file_path = var_functions.query_db_78
print('Loading patent data from:', file_path)

# Load the patent data
with open(file_path, 'r') as f:
    patents = json.load(f)

print('Total patents loaded:', len(patents))

# Function to extract month from grant date string
def extract_month(date_str):
    if not date_str or '2019' not in date_str:
        return None
    date_str_lower = date_str.lower()
    months = {
        'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6,
        'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12
    }
    for abbr, num in months.items():
        if abbr in date_str_lower:
            return num
    return None

# Function to extract CPC level 4 codes (first 4 characters)
def extract_cpc_level4(cpc_json):
    if not cpc_json or cpc_json == '[]':
        return []
    try:
        cpc_list = json.loads(cpc_json)
        codes = set()
        for item in cpc_list:
            if isinstance(item, dict) and 'code' in item:
                code = item['code']
                if len(code) >= 4:
                    codes.add(code[:4])
        return list(codes)
    except:
        return []

# Process patents: count filings per CPC level 4 per month for second half 2019
cpc_monthly_counts = defaultdict(lambda: defaultdict(int))
second_half_patents = 0

for patent in patents:
    date_str = patent.get('grant_date', '')
    month = extract_month(date_str)

    if not month or month < 7:
        continue

    cpc_codes = extract_cpc_level4(patent.get('cpc', ''))
    if not cpc_codes:
        continue

    second_half_patents += 1
    for cpc in cpc_codes:
        cpc_monthly_counts[cpc][month] += 1

print('Second half 2019 patents:', second_half_patents)
print('Unique CPC level 4 codes:', len(cpc_monthly_counts))

# Calculate Exponential Moving Average (EMA) for each CPC code (alpha = 0.1)
alpha = 0.1
best_periods = {}

for cpc in cpc_monthly_counts:
    ema = 0
    best_ema = 0
    best_month = None
    best_count = 0

    for month in range(7, 13):
        count = cpc_monthly_counts[cpc][month]

        if month == 7:
            ema = count
        else:
            ema = alpha * count + (1 - alpha) * ema

        if ema > best_ema:
            best_ema = ema
            best_month = month
            best_count = count

    best_periods[cpc] = {
        'best_ema': best_ema,
        'best_month': best_month,
        'patents_in_month': best_count,
        'monthly_counts': dict(cpc_monthly_counts[cpc])
    }

# Sort CPC codes by best EMA
sorted_cpc = sorted(best_periods.items(), key=lambda x: x[1]['best_ema'], reverse=True)

print('\nTop 15 CPC codes by EMA (second half 2019):')
for i, (cpc, data) in enumerate(sorted_cpc[:15]):
    print('{0:2d}. CPC {1}: EMA={2:.2f}, Best month={3}, Patents={4}'.format(
        i+1, cpc, data['best_ema'], data['best_month'], data['patents_in_month']
    ))

result = {
    'total_patents': second_half_patents,
    'total_cpc_codes': len(cpc_monthly_counts),
    'top_cpc_codes': sorted_cpc[:15],
    'best_periods': best_periods
}

print('\n__RESULT__:')
print(json.dumps(result))

