        count = cpc_monthly_counts[cpc][month]

        if month == 7:
            ema = count
        else:
            ema = alpha * count + (1 - alpha) * ema

        if ema > best_ema:
            best_ema = ema
            best_month = month
            best_count = count

    best_periods[cpc] = {
        'best_ema': best_ema,
        'best_month': best_month,
        'patents_in_month': best_count,
        'monthly_counts': dict(cpc_monthly_counts[cpc])
    }

# Sort CPC codes by best EMA
sorted_cpc = sorted(best_periods.items(), key=lambda x: x[1]['best_ema'], reverse=True)

print('\nTop 15 CPC codes by EMA (second half 2019):')
for i, (cpc, data) in enumerate(sorted_cpc[:15]):
    print('{0:2d}. CPC {1}: EMA={2:.2f}, Best month={3}, Patents={4}'.format(
        i+1, cpc, data['best_ema'], data['best_month'], data['patents_in_month']
    ))

result = {
    'total_patents': second_half_patents,
    'total_cpc_codes': len(cpc_monthly_counts),
    'top_cpc_codes': sorted_cpc[:15],
    'best_periods': best_periods
}

print('\n__RESULT__:')
print(json.dumps(result))

