import json
import re
from collections import defaultdict

# Load the patent data from the file
file_path = '/tmp/tmp4m3n0khf.json'
print('Loading patent data...')

with open(file_path, 'r') as f:
    patents = json.load(f)

print('Patents loaded:', len(patents))

# Define month mapping
months_dict = {'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6, 'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12}

# Helper functions
def get_month(date_str):
    if not date_str:
        return None
    date_lower = date_str.lower()
    for abbr, num in months_dict.items():
        if abbr in date_lower:
            return num
    return None

def get_cpc_level4(cpc_json):
    if not cpc_json or cpc_json == '[]':
        return []
    try:
        cpc_list = json.loads(cpc_json)
        codes = set()
        for item in cpc_list:
            if isinstance(item, dict) and 'code' in item:
                code = item['code']
                if len(code) >= 4:
                    codes.add(code[:4])
        return list(codes)
    except:
        return []

# Count patents by CPC code and month for second half 2019
cpc_month_counts = defaultdict(lambda: defaultdict(int))
second_half_patents = 0

for patent in patents:
    grant_date = patent.get('grant_date', '')
    month = get_month(grant_date)

    # Only process second half of 2019 (July-December)
    if not month or month < 7:
        continue

    cpc_codes = get_cpc_level4(patent.get('cpc', ''))
    if not cpc_codes:
        continue

    second_half_patents += 1
    for cpc in cpc_codes:
        cpc_month_counts[cpc][month] += 1

print('Second half 2019 patents:', second_half_patents)
print('Unique CPC level 4 codes:', len(cpc_month_counts))

# Calculate Exponential Moving Average for each CPC code
alpha = 0.1
ema_results = {}

for cpc in cpc_month_counts:
    ema = 0
    best_ema = 0
    best_month = None

    # Process months July (7) through December (12)
    for month in range(7, 13):
        count = cpc_month_counts[cpc][month]

        if month == 7:
            ema = count
        else:
            ema = alpha * count + (1 - alpha) * ema

        if ema > best_ema:
            best_ema = ema
            best_month = month

    ema_results[cpc] = {
        'best_ema': best_ema,
        'best_month': best_month
    }

# Sort CPC codes by best EMA (descending)
sorted_cpc = sorted(ema_results.items(), key=lambda x: x[1]['best_ema'], reverse=True)

print('Top 15 CPC codes by EMA:')
for i, (cpc, data) in enumerate(sorted_cpc[:15]):
    print(f"{i+1:2d}. CPC {cpc}: EMA={data['best_ema']:.2f}, Best month={data['best_month']}")

# Prepare output
output = {
    'total_patents': second_half_patents,
    'top_cpc_codes': sorted_cpc[:15]
}

print('\n__RESULT__:')
print(json.dumps(output))

