import json
import re
from collections import defaultdict

# Find the correct file path from the storage variables
all_vars = list(locals().keys())
print('Available storage variables:', [v for v in all_vars if 'query_db' in str(v)])

# Look for the most recent query_db variable
file_path = None
for var_name in all_vars:
    if 'query_db' in str(var_name) and '112' not in str(var_name):
        try:
            path = locals()[var_name]
            if isinstance(path, str) and '.json' in path:
                file_path = path
                print('Found file path:', file_path)
                break
        except:
            continue

if not file_path:
    print('Could not find file path')
    exit()

# Load the patent data
print('Loading patent data from:', file_path)
with open(file_path, 'r') as f:
    patents = json.load(f)

print('Total patents loaded:', len(patents))

# Helper function to extract month from grant date
def get_month(date_str):
    if not date_str:
        return None
    date_lower = date_str.lower()
    months = {'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6, 'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12}
    for abbr, num in months.items():
        if abbr in date_lower:
            return num
    return None

# Helper function to extract CPC level 4 codes
def get_cpc_level4(cpc_json):
    if not cpc_json or cpc_json == '[]':
        return []
    try:
        cpc_list = json.loads(cpc_json)
        codes = set()
        for item in cpc_list:
            if isinstance(item, dict) and 'code' in item:
                code = item['code']
                if len(code) >= 4:
                    codes.add(code[:4])
        return list(codes)
    except:
        return []

# Count patents by CPC code and month for second half 2019
cpc_month_counts = defaultdict(lambda: defaultdict(int))
second_half_patents = 0

for patent in patents:
    month = get_month(patent.get('grant_date', ''))
    if not month or month < 7:
        continue

    cpc_codes = get_cpc_level4(patent.get('cpc', ''))
    if cpc_codes:
        second_half_patents += 1
        for cpc in cpc_codes:
            cpc_month_counts[cpc][month] += 1

print('Second half 2019 patents count:', second_half_patents)
print('Unique CPC level 4 codes found:', len(cpc_month_counts))

# Calculate Exponential Moving Average (EMA) for each CPC code
alpha = 0.1
ema_results = {}

for cpc in cpc_month_counts:
    ema = 0
    best_ema = 0
    best_month = None

    for month in range(7, 13):
        count = cpc_month_counts[cpc][month]

        if month == 7:
            ema = count
        else:
            ema = alpha * count + (1 - alpha) * ema

        if ema > best_ema:
            best_ema = ema
            best_month = month

    ema_results[cpc] = {'ema': best_ema, 'month': best_month}

# Sort CPC codes by EMA (descending)
sorted_cpc = sorted(ema_results.items(), key=lambda x: x[1]['ema'], reverse=True)

print('\nTop 15 CPC codes by EMA:')
for i, (cpc, data) in enumerate(sorted_cpc[:15]):
    print(str(i+1) + '. CPC ' + cpc + ': EMA=' + str(round(data['ema'], 2)) + ', Best month=' + str(data['month']))

# Save results for next step
result_data = {
    'total_patents': second_half_patents,
    'top_cpc_codes': sorted_cpc[:15],
    'cpc_month_counts': dict(cpc_month_counts)
}

print('\n__RESULT__:')
print(json.dumps(result_data))

